SELECT COUNT(DISTINCT CHM.SIAPE) AS QUANTIDADE FROM CALC_HORA_AULA_MEDIA CHM JOIN SERVIDOR S ON S.PK_SIAPE = CHM.SIAPE WHERE CHM.ANO = 2020 AND CHM.SEMESTRE = 1 AND LOWER(CHM.SIGLA_CAMPUS) = LOWER('inh') AND LOWER(COALESCE(S.AREA_INGRESSO, '')) LIKE '%geografia%' AND LOWER(COALESCE(S.CONTRATO, '')) = 'efetivos'